/*
 * pl_builtin.c — Prolog builtin predicate implementations
 *
 * write/1    — print a term to stdout
 * writeln/1  — print a term + newline
 * functor/3  — decompose/construct term head
 * arg/3      — nth argument of compound
 * =../2      — univ: Term =.. [Functor|Args]
 * read/1     — stub (returns fail for now)
 *
 * These are called from the code generated by pl_emit.c.
 */

#include "prolog_builtin.h"
#include "prolog_atom.h"
#include "prolog_runtime.h"
#include "term.h"

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>
#include <math.h>

/* =========================================================================
 * pl_write helpers
 * ======================================================================= */
static int pl_op_prec(const char *name, int arity) {
    struct { const char *n; int a; int p; } tbl[] = {
        {":-",2,1200},{";",2,1100},{"->",2,1050},{",",2,1000},
        {"=",2,700},{"\\=",2,700},{"is",2,700},{"=:=",2,700},{"=\\=",2,700},
        {"<",2,700},{">",2,700},{"=<",2,700},{">=",2,700},
        {"==",2,700},{"\\==",2,700},{"@<",2,700},{"@>",2,700},
        {"@=<",2,700},{"@>=",2,700},{"=..",2,700},
        {"+",2,500},{"-",2,500},
        {"*",2,400},{"/",2,400},{"//",2,400},{"mod",2,400},
        {"rem",2,400},{"<<",2,400},{">>",2,400},
        {"**",2,200},{"^",2,200},
        {"-",1,200},{"\\+",1,900},{"not",1,900},
        {NULL,0,0}
    };
    for (int i = 0; tbl[i].n; i++)
        if (tbl[i].a == arity && strcmp(tbl[i].n, name) == 0) return tbl[i].p;
    return -1;
}

/* =========================================================================
 * pl_write — print a term to stdout
 * ======================================================================= */
void pl_write(Term *t) {
    t = term_deref(t);
    if (!t) { printf("[]"); return; }
    switch (t->tag) {
        case TT_ATOM: {
            const char *name = prolog_atom_name(t->atom_id);
            if (!name) name = "?";
            /* Quote atoms that need it (contain spaces or start with upper) */
            int needs_quote = 0;
            if (name[0] && (isupper((unsigned char)name[0]) || name[0] == '_'))
                needs_quote = 1;
            for (const char *p = name; *p && !needs_quote; p++)
                if (!isalnum((unsigned char)*p) && *p != '_')
                    needs_quote = 1;
            if (needs_quote && name[0] != '[') {
                /* Actually: standard Prolog doesn't quote atoms in write/1,
                 * only in writeq/1.  Use writeq behaviour for clarity. */
            }
            printf("%s", name);
            break;
        }
        case TT_VAR:
            /* Unbound variable — print as _GN */
            printf("_G%d", t->var_slot);
            break;
        case TT_INT:
            printf("%ld", t->ival);
            break;
        case TT_FLOAT: {
            double fv = t->fval;
            if (fv == (long)fv && fv >= -1e15 && fv <= 1e15)
                printf("%.1f", fv);
            else
                printf("%g", fv);
            break;
        }
        case TT_COMPOUND: {
            const char *fn = prolog_atom_name(t->compound.functor);
            if (!fn) fn = "?";
            /* List notation: '.'(H, T) -> [H|T] */
            if (t->compound.functor == ATOM_DOT && t->compound.arity == 2) {
                printf("[");
                pl_write(t->compound.args[0]);
                Term *tail = term_deref(t->compound.args[1]);
                while (tail && tail->tag == TT_COMPOUND &&
                       tail->compound.functor == ATOM_DOT &&
                       tail->compound.arity == 2) {
                    printf(",");
                    pl_write(tail->compound.args[0]);
                    tail = term_deref(tail->compound.args[1]);
                }
                if (tail && tail->tag == TT_ATOM && tail->atom_id == ATOM_NIL) {
                    /* clean list end */
                } else {
                    printf("|");
                    pl_write(tail);
                }
                printf("]");
                break;
            }
            /* Operator notation for common binary/unary ops.
             * Standard Prolog operator precedences (lower number = tighter binding).
             * write/1 prints infix without parens unless an argument needs disambiguation. */
            struct { const char *name; int arity; int prec; int right_assoc; } ops[] = {
                {":-",2,1200,1}, {";",2,1100,1}, {"->",2,1050,1},
                {",",2,1000,1},
                {"=",2,700,0},{"\\=",2,700,0},{"is",2,700,0},
                {"=:=",2,700,0},{"=\\=",2,700,0},
                {"<",2,700,0},{">",2,700,0},{"=<",2,700,0},{">=",2,700,0},
                {"==",2,700,0},{"\\==",2,700,0},
                {"@<",2,700,0},{"@>",2,700,0},{"@=<",2,700,0},{"@>=",2,700,0},
                {"=..",2,700,0},
                {"+",2,500,0},{"-",2,500,0},
                {"*",2,400,0},{"/",2,400,0},{"//",2,400,0},{"mod",2,400,0},
                {"rem",2,400,0},{"<<",2,400,0},{">>",2,400,0},
                {"**",2,200,1},{"^",2,200,1},
                {"-",1,200,0},{"\\+",1,900,0},{"not",1,900,0},
                {NULL,0,0,0}
            };
            int is_op = 0;
            for (int i = 0; ops[i].name; i++) {
                if (strcmp(fn, ops[i].name) == 0 && t->compound.arity == ops[i].arity) {
                    is_op = 1;
                    if (ops[i].arity == 2) {
                        /* Left arg: needs parens if it is an op with higher prec number
                         * (lower binding) or same prec and right-associative */
                        Term *larg = term_deref(t->compound.args[0]);
                        Term *rarg = term_deref(t->compound.args[1]);
                        int lp = -1, rp = -1;
                        if (larg && larg->tag == TT_COMPOUND) {
                            const char *lfn = prolog_atom_name(larg->compound.functor);
                            if (lfn) lp = pl_op_prec(lfn, larg->compound.arity);
                        }
                        if (rarg && rarg->tag == TT_COMPOUND) {
                            const char *rfn = prolog_atom_name(rarg->compound.functor);
                            if (rfn) rp = pl_op_prec(rfn, rarg->compound.arity);
                        }
                        int my_prec = ops[i].prec;
                        int lneed = (lp > my_prec) || (lp == my_prec && ops[i].right_assoc);
                        int rneed = (rp > my_prec) || (rp == my_prec && !ops[i].right_assoc);
                        if (lneed) printf("(");
                        pl_write(t->compound.args[0]);
                        if (lneed) printf(")");
                        /* Space around alphabetic operators */
                        if (isalpha((unsigned char)fn[0])) printf(" %s ", fn);
                        else printf("%s", fn);
                        if (rneed) printf("(");
                        pl_write(t->compound.args[1]);
                        if (rneed) printf(")");
                    } else {
                        /* Unary prefix */
                        Term *arg = term_deref(t->compound.args[0]);
                        int ap = -1;
                        if (arg && arg->tag == TT_COMPOUND) {
                            const char *afn = prolog_atom_name(arg->compound.functor);
                            if (afn) ap = pl_op_prec(afn, arg->compound.arity);
                        }
                        int aneed = (ap >= ops[i].prec);
                        if (isalpha((unsigned char)fn[0])) printf("%s ", fn);
                        else printf("%s", fn);
                        if (aneed) printf("(");
                        pl_write(t->compound.args[0]);
                        if (aneed) printf(")");
                    }
                    break;
                }
            }
            if (!is_op) {
                printf("%s(", fn);
                for (int i = 0; i < t->compound.arity; i++) {
                    if (i) printf(",");
                    pl_write(t->compound.args[i]);
                }
                printf(")");
            }
            break;
        }
        case TT_REF:
            pl_write(t->ref);  /* should not happen after term_deref */
            break;
    }
}

void pl_writeln(Term *t) {
    pl_write(t);
    printf("\n");
}

/* =========================================================================
 * pl_functor — functor(Term, Name, Arity)
 *
 * Rung-9 builtin.  If Term is bound:
 *   atom:     Name=atom_name, Arity=0
 *   compound: Name=functor_atom, Arity=n
 *   integer:  Name=integer, Arity=0
 * If Term is unbound and Name+Arity are bound: construct the term.
 * ======================================================================= */
int pl_functor(Term *t, Term *name, Term *arity, Trail *tr) {
    t     = term_deref(t);
    name  = term_deref(name);
    arity = term_deref(arity);

    if (t && t->tag != TT_VAR) {
        /* Decompose mode */
        Term *name_term  = NULL;
        Term *arity_term = NULL;
        switch (t->tag) {
            case TT_ATOM:
                name_term  = term_new_atom(t->atom_id);
                arity_term = term_new_int(0);
                break;
            case TT_INT:
                name_term  = term_new_int(t->ival);
                arity_term = term_new_int(0);
                break;
            case TT_FLOAT:
                name_term  = term_new_float(t->fval);
                arity_term = term_new_int(0);
                break;
            case TT_COMPOUND:
                name_term  = term_new_atom(t->compound.functor);
                arity_term = term_new_int(t->compound.arity);
                break;
            default:
                return 0;
        }
        int mark = trail_mark(tr);
        if (!unify(name, name_term, tr) || !unify(arity, arity_term, tr)) {
            trail_unwind(tr, mark);
            return 0;
        }
        return 1;
    } else {
        /* Construct mode: Name and Arity must be bound */
        if (!name || name->tag == TT_VAR) return 0;
        if (!arity || arity->tag != TT_INT) return 0;
        long ar = arity->ival;
        Term *new_t;
        if (ar == 0) {
            if (name->tag == TT_ATOM) new_t = term_new_atom(name->atom_id);
            else if (name->tag == TT_INT) new_t = term_new_int(name->ival);
            else return 0;
        } else {
            if (name->tag != TT_ATOM) return 0;
            /* Build compound with unbound var args */
            Term **args = malloc(ar * sizeof(Term *));
            for (int i = 0; i < ar; i++) args[i] = term_new_var(i);
            new_t = term_new_compound(name->atom_id, (int)ar, args);
            free(args);
        }
        int mark = trail_mark(tr);
        if (!unify(t, new_t, tr)) {
            trail_unwind(tr, mark);
            return 0;
        }
        return 1;
    }
}

/* =========================================================================
 * pl_arg — arg(N, Term, Arg)
 * ======================================================================= */
int pl_arg(Term *n, Term *compound, Term *arg, Trail *tr) {
    n        = term_deref(n);
    compound = term_deref(compound);

    if (!n || n->tag != TT_INT) return 0;
    if (!compound || compound->tag != TT_COMPOUND) return 0;
    long idx = n->ival;  /* 1-based */
    if (idx < 1 || idx > compound->compound.arity) return 0;

    int mark = trail_mark(tr);
    if (!unify(arg, compound->compound.args[idx - 1], tr)) {
        trail_unwind(tr, mark);
        return 0;
    }
    return 1;
}

/* =========================================================================
 * pl_univ — Term =.. List  (univ / =..)
 *
 * foo(a,b) =.. [foo, a, b]
 * foo      =.. [foo]
 * ======================================================================= */

/* Build a Prolog list from args array */
static Term *make_list(int n, Term **items) {
    Term *tail = term_new_atom(ATOM_NIL);
    for (int i = n - 1; i >= 0; i--) {
        Term *args[2] = { items[i], tail };
        tail = term_new_compound(ATOM_DOT, 2, args);
    }
    return tail;
}

/* Count list length; return -1 if not a proper list */
static int list_len(Term *t) {
    int n = 0;
    while (1) {
        t = term_deref(t);
        if (!t) return -1;
        if (t->tag == TT_ATOM && t->atom_id == ATOM_NIL) return n;
        if (t->tag != TT_COMPOUND || t->compound.functor != ATOM_DOT ||
            t->compound.arity != 2) return -1;
        n++;
        t = t->compound.args[1];
    }
}

int pl_univ(Term *t, Term *list, Trail *tr) {
    t    = term_deref(t);
    list = term_deref(list);

    if (t && t->tag != TT_VAR) {
        /* Decompose: T =.. L */
        Term *result;
        if (t->tag == TT_ATOM) {
            Term *items[1] = { term_new_atom(t->atom_id) };
            result = make_list(1, items);
        } else if (t->tag == TT_INT) {
            Term *items[1] = { term_new_int(t->ival) };
            result = make_list(1, items);
        } else if (t->tag == TT_COMPOUND) {
            int arity = t->compound.arity;
            Term **items = malloc((arity + 1) * sizeof(Term *));
            items[0] = term_new_atom(t->compound.functor);
            for (int i = 0; i < arity; i++) items[i + 1] = t->compound.args[i];
            result = make_list(arity + 1, items);
            free(items);
        } else return 0;
        int mark = trail_mark(tr);
        if (!unify(list, result, tr)) { trail_unwind(tr, mark); return 0; }
        return 1;
    } else {
        /* Construct: T =.. L, L must be bound */
        if (!list || list->tag != TT_COMPOUND || list->compound.functor != ATOM_DOT)
            return 0;
        int len = list_len(list);
        if (len < 1) return 0;
        /* Extract functor and args */
        Term *head_item = term_deref(list->compound.args[0]);
        if (!head_item || head_item->tag != TT_ATOM) return 0;
        int functor_id = head_item->atom_id;
        int arity = len - 1;
        Term *new_t;
        if (arity == 0) {
            new_t = term_new_atom(functor_id);
        } else {
            Term **args = malloc(arity * sizeof(Term *));
            Term *cur = term_deref(list->compound.args[1]);
            for (int i = 0; i < arity; i++) {
                args[i] = term_deref(cur->compound.args[0]);
                cur = term_deref(cur->compound.args[1]);
            }
            new_t = term_new_compound(functor_id, arity, args);
            free(args);
        }
        int mark = trail_mark(tr);
        if (!unify(t, new_t, tr)) { trail_unwind(tr, mark); return 0; }
        return 1;
    }
}

/* =========================================================================
 * pl_read — stub: always fails
 * ======================================================================= */
int pl_read(Term *result, Trail *tr) {
    (void)result; (void)tr;
    return 0;  /* not implemented in M-PROLOG-R1 */
}

/* =========================================================================
 * Arithmetic evaluation — is/2
 * ======================================================================= */

static int _aid_plus=-1, _aid_minus=-1, _aid_times=-1, _aid_div=-1, _aid_mod=-1;
static void arith_atoms_init(void) {
    if (_aid_plus >= 0) return;
    _aid_plus  = prolog_atom_intern("+");
    _aid_minus = prolog_atom_intern("-");
    _aid_times = prolog_atom_intern("*");
    _aid_div   = prolog_atom_intern("/");
    _aid_mod   = prolog_atom_intern("mod");
}

/* Type-preserving arithmetic evaluator — returns Term* (TT_INT or TT_FLOAT) */
static Term *pl_eval_arith_term(Term *t) {
    static int _aid_pow = -1, _aid_idiv = -1, _aid_sqrt = -1, _aid_log = -1,
               _aid_exp = -1, _aid_sin = -1, _aid_cos = -1, _aid_abs = -1,
               _aid_max = -1, _aid_min = -1, _aid_truncate = -1,
               _aid_round = -1, _aid_ceiling = -1, _aid_floor = -1,
               _aid_float = -1, _aid_float_int = -1,
               _aid_band = -1, _aid_bor = -1, _aid_bxor = -1,
               _aid_lshift = -1, _aid_rshift = -1, _aid_bnot = -1,
               _aid_msb = -1, _aid_pi = -1, _aid_e = -1;
    arith_atoms_init();
    if (_aid_pow < 0) {
        _aid_pow      = prolog_atom_intern("**");
        _aid_idiv     = prolog_atom_intern("//");
        _aid_sqrt     = prolog_atom_intern("sqrt");
        _aid_log      = prolog_atom_intern("log");
        _aid_exp      = prolog_atom_intern("exp");
        _aid_sin      = prolog_atom_intern("sin");
        _aid_cos      = prolog_atom_intern("cos");
        _aid_abs      = prolog_atom_intern("abs");
        _aid_max      = prolog_atom_intern("max");
        _aid_min      = prolog_atom_intern("min");
        _aid_truncate = prolog_atom_intern("truncate");
        _aid_round    = prolog_atom_intern("round");
        _aid_ceiling  = prolog_atom_intern("ceiling");
        _aid_floor    = prolog_atom_intern("floor");
        _aid_float    = prolog_atom_intern("float");
        _aid_float_int= prolog_atom_intern("float_integer_part");
        _aid_band     = prolog_atom_intern("/\\");
        _aid_bor      = prolog_atom_intern("\\/");
        _aid_bxor     = prolog_atom_intern("xor");
        _aid_lshift   = prolog_atom_intern("<<");
        _aid_rshift   = prolog_atom_intern(">>");
        _aid_bnot     = prolog_atom_intern("\\");
        _aid_msb      = prolog_atom_intern("msb");
        _aid_pi       = prolog_atom_intern("pi");
        _aid_e        = prolog_atom_intern("e");
    }
    t = term_deref(t);
    if (!t) return term_new_int(0);
    switch (t->tag) {
        case TT_INT:   return t;
        case TT_FLOAT: return t;
        case TT_ATOM:
            if (t->atom_id == _aid_pi) return term_new_float(M_PI);
            if (t->atom_id == _aid_e)  return term_new_float(M_E);
            return term_new_int(0);
        case TT_COMPOUND: {
            int f = t->compound.functor;
            int a = t->compound.arity;
            if (a == 2) {
                Term *lv = pl_eval_arith_term(t->compound.args[0]);
                Term *rv = pl_eval_arith_term(t->compound.args[1]);
                int is_float = (lv->tag == TT_FLOAT || rv->tag == TT_FLOAT);
                double ld = (lv->tag == TT_FLOAT) ? lv->fval : (double)lv->ival;
                double rd = (rv->tag == TT_FLOAT) ? rv->fval : (double)rv->ival;
                long   li = (lv->tag == TT_INT)   ? lv->ival : (long)lv->fval;
                long   ri = (rv->tag == TT_INT)   ? rv->ival : (long)rv->fval;
                if (f == _aid_plus)   return is_float ? term_new_float(ld+rd) : term_new_int(li+ri);
                if (f == _aid_minus)  return is_float ? term_new_float(ld-rd) : term_new_int(li-ri);
                if (f == _aid_times)  return is_float ? term_new_float(ld*rd) : term_new_int(li*ri);
                if (f == _aid_div)    return is_float ? term_new_float(rd?ld/rd:0) : term_new_int(ri?li/ri:0);
                if (f == _aid_mod)    return term_new_int(ri ? li % ri : 0);
                if (f == _aid_idiv)   return term_new_int(ri ? li / ri : 0);
                if (f == _aid_pow)    return term_new_float(pow(ld, rd));
                if (f == _aid_max)    return is_float ? (ld>=rd?lv:rv) : (li>=ri?lv:rv);
                if (f == _aid_min)    return is_float ? (ld<=rd?lv:rv) : (li<=ri?lv:rv);
                if (f == _aid_band)   return term_new_int(li & ri);
                if (f == _aid_bor)    return term_new_int(li | ri);
                if (f == _aid_bxor)   return term_new_int(li ^ ri);
                if (f == _aid_lshift) return term_new_int(li << ri);
                if (f == _aid_rshift) return term_new_int(li >> ri);
            }
            if (a == 1) {
                Term *v = pl_eval_arith_term(t->compound.args[0]);
                double d = (v->tag == TT_FLOAT) ? v->fval : (double)v->ival;
                long   i = (v->tag == TT_INT)   ? v->ival : (long)v->fval;
                if (f == _aid_minus)    return (v->tag==TT_FLOAT) ? term_new_float(-d) : term_new_int(-i);
                if (f == _aid_abs)      return (v->tag==TT_FLOAT) ? term_new_float(fabs(d)) : term_new_int(i<0?-i:i);
                if (f == _aid_sqrt)     return term_new_float(sqrt(d));
                if (f == _aid_log)      return term_new_float(log(d));
                if (f == _aid_exp)      return term_new_float(exp(d));
                if (f == _aid_sin)      return term_new_float(sin(d));
                if (f == _aid_cos)      return term_new_float(cos(d));
                if (f == _aid_truncate) return term_new_int((long)d);
                if (f == _aid_round)    return term_new_int((long)round(d));
                if (f == _aid_ceiling)  return term_new_int((long)ceil(d));
                if (f == _aid_floor)    return term_new_int((long)floor(d));
                if (f == _aid_float)    return term_new_float(d);
                if (f == _aid_float_int)return term_new_float(trunc(d));
                if (f == _aid_bnot)     return term_new_int(~i);
                if (f == _aid_msb)      return term_new_int(i>0 ? 63 - __builtin_clzl(i) : -1);
            }
            return term_new_int(0);
        }
        default: return term_new_int(0);
    }
}

/* Legacy integer evaluator — still used by comparisons */
long pl_eval_arith(Term *t) {
    Term *r = pl_eval_arith_term(t);
    if (!r) return 0;
    return (r->tag == TT_FLOAT) ? (long)r->fval : r->ival;
}

/* Floating-point version for mixed-type comparisons */
static double pl_eval_dbl(Term *t) {
    Term *r = pl_eval_arith_term(t);
    if (!r) return 0.0;
    return (r->tag == TT_FLOAT) ? r->fval : (double)r->ival;
}

/* is/2: Result is Expr — unify Result with correctly-typed evaluated term */
int pl_is(Term *result, Term *expr, Trail *trail) {
    Term *val = pl_eval_arith_term(expr);
    return unify(result, val, trail);
}

/* Numeric comparisons — use double to handle int/float mixing */
int pl_num_lt(Term *a, Term *b)  { return pl_eval_dbl(a) <  pl_eval_dbl(b); }
int pl_num_gt(Term *a, Term *b)  { return pl_eval_dbl(a) >  pl_eval_dbl(b); }
int pl_num_le(Term *a, Term *b)  { return pl_eval_dbl(a) <= pl_eval_dbl(b); }
int pl_num_ge(Term *a, Term *b)  { return pl_eval_dbl(a) >= pl_eval_dbl(b); }
int pl_num_eq(Term *a, Term *b)  { return pl_eval_dbl(a) == pl_eval_dbl(b); }
int pl_num_ne(Term *a, Term *b)  { return pl_eval_dbl(a) != pl_eval_dbl(b); }

/* Type-test builtins — return 1 (true) or 0 (false), no Trail needed */
int pl_atom(Term *t)     { t = term_deref(t); return t && t->tag == TT_ATOM; }
int pl_integer(Term *t)  { t = term_deref(t); return t && t->tag == TT_INT; }
int pl_is_float(Term *t) { t = term_deref(t); return t && t->tag == TT_FLOAT; }
int pl_var(Term *t)      { t = term_deref(t); return !t || t->tag == TT_VAR; }
int pl_nonvar(Term *t)   { t = term_deref(t); return t && t->tag != TT_VAR; }
int pl_compound(Term *t) { t = term_deref(t); return t && t->tag == TT_COMPOUND; }
int pl_callable(Term *t) { t = term_deref(t); return t && (t->tag == TT_ATOM || t->tag == TT_COMPOUND); }
